code_snippets.classify_diagram:
// Classify a DiagramState into entity counts and flags
function classifyDiagram(diagram) {
  const counts = {};
  const flags  = {};
  diagram.nodes.forEach(n => {
    counts[n.type] = (counts[n.type] || 0) + 1;
  });
  flags.num_lenders   = (counts.lender || 0) + (counts.mla || 0) + (counts.dfi || 0);
  flags.num_sponsors  = counts.sponsor  || 0;
  flags.has_spv       = !!counts.spv;
  flags.has_dfi       = !!counts.dfi;
  flags.has_govt      = !!counts.govt;
  flags.has_epc       = !!counts.epc;
  flags.has_om        = !!counts.om;
  flags.has_offtaker  = !!counts.offtaker;
  flags.has_dsra      = !!counts.dsra;
  flags.has_insurance = !!counts.insurance;
  flags.has_mla       = !!counts.mla;
  return flags;
}

code_snippets.select_documents:
// Decide which contract documents to generate
function selectDocuments(flags) {
  const docs = [];
  if (flags.has_spv && flags.num_lenders > 0) docs.push('Facility Agreement');
  if (flags.num_lenders >= 2 || flags.has_dfi)  docs.push('Common Terms Agreement');
  if (flags.num_lenders >= 2)                   docs.push('Intercreditor Agreement');
  if (flags.has_epc)     docs.push('Direct Agreement — EPC Contractor');
  if (flags.has_om)      docs.push('Direct Agreement — O&M Operator');
  if (flags.has_offtaker)docs.push('Direct Agreement — Offtaker / PPA');
  if (flags.has_govt)    docs.push('Direct Agreement — Concession / PPP');
  docs.push('Security Trust Deed');
  docs.push('Accounts Agreement');
  return docs;
}

code_snippets.extract_parties:
// Map diagram nodes to legal parties for a given document type
function extractParties(nodes, documentType) {
  const roleMap = {
    spv:       "Borrower",
    sponsor:   "Sponsor",
    lender:    "Senior Lender",
    mla:       "Mandated Lead Arranger",
    dfi:       "DFI Lender",
    offtaker:  "Offtaker",
    epc:       "EPC Contractor",
    om:        "O&M Operator",
    govt:      "Contracting Authority",
    insurance: "Insurer",
    dsra:      "Account Bank",
    custom:    "Party",
  };

  const relevantTypes = {
    "Facility Agreement":         ["spv","lender","mla","dfi"],
    "Common Terms Agreement":     ["spv","lender","mla","dfi"],
    "Intercreditor Agreement":    ["lender","mla","dfi"],
    "Direct Agreement — EPC":     ["spv","epc","lender","mla"],
    "Direct Agreement — O&M":     ["spv","om","lender","mla"],
    "Direct Agreement — Offtaker":["spv","offtaker","lender","mla"],
    "Security Trust Deed":        ["spv","lender","mla","dfi","sponsor"],
    "Accounts Agreement":         ["spv","dsra","lender","mla"],
  };

  const relevant = relevantTypes[documentType] || Object.keys(roleMap);
  return nodes
    .filter(n => relevant.includes(n.type))
    .map(n => ({ name: n.name, role: roleMap[n.type] || "Party", type: n.type }));
}

code_snippets.populate_clause:
// Fill a clause template with actual values from diagram + assumptions
function populateClause(clauseTemplate, diagram, assumptions) {
  const spv      = diagram.nodes.find(n => n.type === "spv");
  const sponsors = diagram.nodes.filter(n => n.type === "sponsor");
  const lenders  = diagram.nodes.filter(n => n.type === "lender" || n.type === "mla" || n.type === "dfi");

  const totalEV  = assumptions.total_ev || diagram.metadata?.totalEV || "[●]";
  const debtPct  = assumptions.debt_percentage || 0.7;
  const equityPct = 1 - debtPct;

  const vars = {
    "{{BORROWER_NAME}}":       spv?.name || "[PROJECT CO. NAME]",
    "{{SPONSOR_NAMES}}":       sponsors.map(s => s.name).join(" and ") || "[SPONSOR]",
    "{{LENDER_NAMES}}":        lenders.map(l => l.name).join(", ") || "[LENDER]",
    "{{CURRENCY}}":            assumptions.currency || "USD",
    "{{FACILITY_AMOUNT}}":     (totalEV * debtPct).toLocaleString() || "[●]",
    "{{EQUITY_AMOUNT}}":       (totalEV * equityPct).toLocaleString() || "[●]",
    "{{TOTAL_EV}}":            totalEV.toLocaleString?.() || totalEV,
    "{{DEBT_PCT}}":            (debtPct * 100).toFixed(0) + "%",
    "{{EQUITY_PCT}}":          (equityPct * 100).toFixed(0) + "%",
    "{{MARGIN}}":              assumptions.interest_margin || "[●]",
    "{{FLOATING_RATE_INDEX}}": assumptions.floating_rate  || "SOFR",
    "{{TENOR}}":               assumptions.tenor_years    || "[●]",
    "{{DSCR_MINIMUM}}":        assumptions.dscr_target    || "1.20",
    "{{DSCR_SCULPTING_TARGET}}": (parseFloat(assumptions.dscr_target || 1.25) + 0.05).toFixed(2),
    "{{LLCR_MINIMUM}}":        assumptions.llcr_minimum   || "1.15",
    "{{GEARING_MAX}}":         ((debtPct) * 100).toFixed(0),
    "{{DSRA_MONTHS}}":         assumptions.dsra_months    || "6",
    "{{EQUITY_CURE_MAX}}":     "2",
    "{{CASH_SWEEP_PCT}}":      assumptions.cash_sweep_pct || "100",
    "{{GOVERNING_LAW}}":       assumptions.governing_law  || "English law",
    "{{JURISDICTION_COURTS}}": assumptions.jurisdiction   || "England and Wales",
    "{{ACCOUNTING_STANDARD}}": "IFRS",
    "{{DEFAULT_MARGIN}}":      "2",
    "{{CROSS_DEFAULT_THRESHOLD}}": "[●]",
    "{{ABANDONMENT_DAYS}}":    "90",
    "{{FORCE_MAJEURE_MONTHS}}":"6",
    "{{DISTRIBUTION_DSCR_TEST}}": assumptions.distribution_dscr || "1.15",
    "{{AVAILABILITY_END_DATE}}": "[●]",
    "{{GOVERNING_LAW_CITY}}":  "London",
    "{{COD_DATE_OR_PLACEHOLDER}}": assumptions.cod_date || "[●]",
    "{{PROJECT_DESCRIPTION}}": assumptions.project_description || "[PROJECT DESCRIPTION]",
    "{{PROJECT_DOCUMENTS_LIST}}": "[PPA, EPC Contract, O&M Agreement, Concession Agreement]",
    "{{ACCOUNT_BANK}}":        diagram.nodes.find(n => n.type === "dsra")?.name || "[ACCOUNT BANK]",
    "{{ARRANGEMENT_FEE}}":     "[●]",
    "{{AGENCY_FEE}}":          "[●]",
    "{{COMMITMENT_FEE_PCT}}":  "0.50",
    "{{DSRA_REPLENISHMENT_DAYS}}": "30",
    "{{MMRA_ANNUAL_CONTRIBUTION}}": "[●]",
    "{{EQUATOR_PRINCIPLES_IF_APPLICABLE}}": " and the Equator Principles (where applicable)",
  };

  let result = clauseTemplate;
  for (const [key, val] of Object.entries(vars)) {
    result = result.replaceAll(key, val);
  }
  return result;
}

code_snippets.generate_minutes_full:
// Main entry point: DiagramState + PFAssumptions → GeneratedMinutes
function generateMinutes(diagram, assumptions) {
  const flags = classifyDiagram(diagram);
  const docTypes = selectDocuments(flags);

  const documents = docTypes.map(docType => {
    const parties  = extractParties(diagram.nodes, docType);
    const clauses  = CLAUSE_LIBRARY[docType] || [];

    const filledClauses = clauses.map(cl => ({
      number: cl.number,
      title:  cl.title,
      text:   populateClause(cl.template, diagram, assumptions),
    }));

    const partiesBlock = parties
      .map(p => `(${parties.indexOf(p)+1}) **${p.name}** (the '${p.role}')`)
      .join(";
");

    const markdown = renderDocumentToMarkdown({
      docType, partiesBlock, filledClauses, diagram, assumptions,
    });

    return { type: docType, parties, clauses: filledClauses, markdown };
  });

  return {
    diagram_id:   diagram.id,
    documents,
    generated_at: new Date().toISOString(),
  };
}
